import React, { useState, useEffect } from 'react';
import { getDSAProblems, addDSAProblem, updateDSAProblem, deleteDSAProblem, getDSAStats } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import './DSAPractice.css';
import {
  FiClock,
  FiEdit3,
  FiExternalLink,
  FiFilter,
  FiLayers,
  FiSearch,
  FiSliders,
  FiTrash2,
} from 'react-icons/fi';

const PATTERNS = ['Sliding Window','Two Pointer','Binary Search','Graph BFS/DFS','Dynamic Programming','Greedy','Backtracking','Divide and Conquer','Heap/Priority Queue','Trie','Union Find','Monotonic Stack','Prefix Sum','Bit Manipulation','Math'];
const TOPICS = ['Arrays','Strings','Linked List','Trees','Graphs','Stack/Queue','Hashing','Recursion','Sorting','Other'];
const DIFFICULTIES = ['Easy','Medium','Hard'];
const STATUS_OPTS = ['Solved','Attempted','To Review'];
const DIFF_COLOR = { Easy: 'tag-green', Medium: 'tag-orange', Hard: 'tag-red' };
const CARD_ACCENTS = [
  { color: '#06b6d4', soft: 'rgba(6,182,212,0.25)' },
  { color: '#3b82f6', soft: 'rgba(59,130,246,0.25)' },
  { color: '#10b981', soft: 'rgba(16,185,129,0.25)' },
  { color: '#f59e0b', soft: 'rgba(245,158,11,0.25)' },
  { color: '#ec4899', soft: 'rgba(236,72,153,0.25)' },
  { color: '#8b5cf6', soft: 'rgba(139,92,246,0.25)' },
];

const EMPTY_FORM = {
  title: '', link: '', difficulty: 'Medium', patternUsed: 'Dynamic Programming',
  topic: 'Arrays', learningInsight: '', mistakesMade: '', optimizationIdea: '',
  timeTaken: '', status: 'Solved',
};

export default function DSAPractice() {
  const { refreshUser } = useAuth();
  const [problems, setProblems] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState(EMPTY_FORM);
  const [editingId, setEditingId] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [filter, setFilter] = useState({ pattern: '', difficulty: '', status: '' });
  const [search, setSearch] = useState('');
  const [sortBy, setSortBy] = useState('newest');
  const [staggerKey, setStaggerKey] = useState(0);

  useEffect(() => { loadData(); }, [filter]);

  useEffect(() => {
    setStaggerKey((prev) => prev + 1);
  }, [filter.pattern, filter.difficulty, filter.status, search, sortBy, problems]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [pRes, sRes] = await Promise.all([getDSAProblems(filter), getDSAStats()]);
      setProblems(pRes.data.problems);
      setStats(sRes.data);
    } catch (e) { toast.error('Failed to load'); }
    finally { setLoading(false); }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      if (editingId) {
        await updateDSAProblem(editingId, {
          ...form,
          timeTaken: form.timeTaken === '' ? 0 : Number(form.timeTaken),
        });
        toast.success('Problem updated');
      } else {
        const res = await addDSAProblem({
          ...form,
          timeTaken: form.timeTaken === '' ? 0 : Number(form.timeTaken),
        });
        await refreshUser();
        toast.success(`Problem logged! +${res.data.xpEarned} XP 🎯`);
        if (res.data.newBadges?.length) {
          res.data.newBadges.forEach(b => toast.success(`Badge earned: ${b.icon} ${b.name}!`));
        }
      }
      setShowModal(false);
      setEditingId(null);
      setForm(EMPTY_FORM);
      loadData();
    } catch (e) {
      toast.error(e.response?.data?.message || (editingId ? 'Error updating problem' : 'Error adding problem'));
    } finally { setSubmitting(false); }
  };

  const handleStartEdit = (problem) => {
    setEditingId(problem._id);
    setForm({
      title: problem.title || '',
      link: problem.link || '',
      difficulty: problem.difficulty || 'Medium',
      patternUsed: problem.patternUsed || 'Dynamic Programming',
      topic: problem.topic || 'Arrays',
      learningInsight: problem.learningInsight || '',
      mistakesMade: problem.mistakesMade || '',
      optimizationIdea: problem.optimizationIdea || '',
      timeTaken: problem.timeTaken || '',
      status: problem.status || 'Solved',
    });
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Delete this problem?')) return;
    await deleteDSAProblem(id);
    toast.success('Deleted');
    loadData();
  };

  const visibleProblems = problems
    .filter((p) => {
      const q = search.trim().toLowerCase();
      if (!q) return true;
      return (
        p.title.toLowerCase().includes(q)
        || p.patternUsed.toLowerCase().includes(q)
        || p.topic.toLowerCase().includes(q)
      );
    })
    .sort((a, b) => {
      if (sortBy === 'difficulty') {
        const order = { Easy: 1, Medium: 2, Hard: 3 };
        return (order[b.difficulty] || 0) - (order[a.difficulty] || 0);
      }
      if (sortBy === 'xp') {
        return (b.xpEarned || 0) - (a.xpEarned || 0);
      }
      return new Date(b.createdAt || 0) - new Date(a.createdAt || 0);
    });

  return (
    <div className="dsa-practice-page">
      <div className="page-header flex-between" style={{ flexWrap: 'wrap', gap: '1rem' }}>
        <div>
          <h1>🧩 DSA Practice</h1>
          <p>Log problems with pattern recognition and learning insights</p>
        </div>
        <button
          className="btn btn-primary"
          onClick={() => {
            setEditingId(null);
            setForm(EMPTY_FORM);
            setShowModal(true);
          }}
        >
          + Log Problem
        </button>
      </div>

      {/* Stats row */}
      {stats && (
        <div className="grid-4 mb-3">
          <StatMini label="Total Solved" value={stats.total} icon="🧩" />
          <StatMini label="Easy" value={stats.difficultyStats?.Easy || 0} icon="🟢" />
          <StatMini label="Medium" value={stats.difficultyStats?.Medium || 0} icon="🟡" />
          <StatMini label="Hard" value={stats.difficultyStats?.Hard || 0} icon="🔴" />
        </div>
      )}

      {/* Filters */}
      <div className="card mb-2 dsa-toolbar">
        <div className="search-wrap">
          <FiSearch />
          <input
            className="toolbar-search"
            placeholder="Search by title, pattern, or topic"
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>

        <div className="toolbar-controls">
          <div className="select-shell">
            <span className="select-label"><FiLayers /> Pattern</span>
            <select className="form-select" style={{ width: 'auto' }} value={filter.pattern}
              onChange={e => setFilter({ ...filter, pattern: e.target.value })}>
              <option value="">All Patterns</option>
              {PATTERNS.map(p => <option key={p}>{p}</option>)}
            </select>
          </div>
          <div className="select-shell">
            <span className="select-label"><FiSliders /> Sort</span>
            <select className="form-select" style={{ width: 'auto' }} value={sortBy}
              onChange={e => setSortBy(e.target.value)}>
              <option value="newest">Newest</option>
              <option value="difficulty">Difficulty</option>
              <option value="xp">XP Earned</option>
            </select>
          </div>
          {(filter.pattern || filter.difficulty || filter.status || search) &&
            <button className="btn btn-outline btn-sm" onClick={() => {
              setFilter({ pattern: '', difficulty: '', status: '' });
              setSearch('');
            }}>
              Clear
            </button>
          }
        </div>

        <div className="modern-filter-row">
          <div className="modern-filter-group">
            <span className="group-title">Difficulty</span>
            <div className="quick-pill-row">
              {['All', ...DIFFICULTIES].map((difficulty) => {
                const active = (difficulty === 'All' && !filter.difficulty) || filter.difficulty === difficulty;
                return (
                  <button
                    key={difficulty}
                    type="button"
                    className={`quick-pill ${active ? 'active' : ''}`}
                    onClick={() => setFilter({ ...filter, difficulty: difficulty === 'All' ? '' : difficulty })}
                  >
                    {difficulty}
                  </button>
                );
              })}
            </div>
          </div>
          <div className="modern-filter-group">
            <span className="group-title">Status</span>
            <div className="quick-pill-row">
              {['All', ...STATUS_OPTS].map((status) => {
                const active = (status === 'All' && !filter.status) || filter.status === status;
                return (
                  <button
                    key={status}
                    type="button"
                    className={`quick-pill ${active ? 'active' : ''}`}
                    onClick={() => setFilter({ ...filter, status: status === 'All' ? '' : status })}
                  >
                    {status}
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        <div className="pattern-chip-row">
          <span className="chip-label"><FiFilter /> Quick Pattern:</span>
          {PATTERNS.slice(0, 6).map((pattern) => (
            <button
              key={pattern}
              type="button"
              className={`pattern-chip ${filter.pattern === pattern ? 'active' : ''}`}
              onClick={() => setFilter({ ...filter, pattern: filter.pattern === pattern ? '' : pattern })}
            >
              {pattern}
            </button>
          ))}
        </div>

        <div className="filter-summary">
          Showing {visibleProblems.length} of {problems.length} problems
        </div>
      </div>

      {/* Problems list */}
      {loading ? <div className="spinner" /> : (
        <div className="problems-grid">
          {visibleProblems.map((p, idx) => (
            <ProblemCard
              key={`${p._id}-${staggerKey}`}
              problem={p}
              onDelete={handleDelete}
              onEdit={handleStartEdit}
              staggerIndex={Math.min(idx, 10)}
            />
          ))}
          {visibleProblems.length === 0 && (
            <div className="empty-state" style={{ gridColumn: '1/-1' }}>
              <div className="empty-icon">🧩</div>
              <h3>{problems.length ? 'No matching problems' : 'No problems logged yet'}</h3>
              <p>{problems.length ? 'Try changing search/filter options.' : 'Click "Log Problem" to start tracking your DSA journey'}</p>
            </div>
          )}
        </div>
      )}

      {/* Add Problem Modal */}
      {showModal && (
        <div
          className="modal-overlay"
          onClick={(e) => {
            if (e.target === e.currentTarget) {
              setShowModal(false);
              setEditingId(null);
              setForm(EMPTY_FORM);
            }
          }}
        >
          <div className="modal" style={{ maxWidth: '680px' }}>
            <div className="modal-header">
              <span className="modal-title">{editingId ? '✏️ Edit Problem' : '🧩 Log New Problem'}</span>
              <button
                className="modal-close"
                onClick={() => {
                  setShowModal(false);
                  setEditingId(null);
                  setForm(EMPTY_FORM);
                }}
              >
                ×
              </button>
            </div>
            <form onSubmit={handleSubmit}>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">Problem Title *</label>
                  <input className="form-input" placeholder="e.g. Two Sum" value={form.title}
                    onChange={e => setForm({ ...form, title: e.target.value })} required />
                </div>
                <div className="form-group">
                  <label className="form-label">LeetCode Link</label>
                  <input className="form-input" placeholder="https://leetcode.com/..." value={form.link}
                    onChange={e => setForm({ ...form, link: e.target.value })} />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">Difficulty *</label>
                  <select className="form-select" value={form.difficulty} onChange={e => setForm({ ...form, difficulty: e.target.value })}>
                    {DIFFICULTIES.map(d => <option key={d}>{d}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Status</label>
                  <select className="form-select" value={form.status} onChange={e => setForm({ ...form, status: e.target.value })}>
                    {STATUS_OPTS.map(s => <option key={s}>{s}</option>)}
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label className="form-label">Pattern Used *</label>
                  <select className="form-select" value={form.patternUsed} onChange={e => setForm({ ...form, patternUsed: e.target.value })}>
                    {PATTERNS.map(p => <option key={p}>{p}</option>)}
                  </select>
                </div>
                <div className="form-group">
                  <label className="form-label">Topic</label>
                  <select className="form-select" value={form.topic} onChange={e => setForm({ ...form, topic: e.target.value })}>
                    {TOPICS.map(t => <option key={t}>{t}</option>)}
                  </select>
                </div>
              </div>

              <div className="insight-section">
                <div className="insight-header">💡 Learning Insights</div>
                <div className="form-group">
                  <label className="form-label">What did you learn?</label>
                  <textarea className="form-textarea" placeholder="Key takeaways from solving this problem..."
                    value={form.learningInsight} onChange={e => setForm({ ...form, learningInsight: e.target.value })} />
                </div>
                <div className="form-group">
                  <label className="form-label">Mistakes Made</label>
                  <textarea className="form-textarea" placeholder="Edge cases missed, wrong approach..."
                    value={form.mistakesMade} onChange={e => setForm({ ...form, mistakesMade: e.target.value })} />
                </div>
                <div className="form-group">
                  <label className="form-label">Optimization Idea</label>
                  <textarea className="form-textarea" placeholder="How could this be further optimized?"
                    value={form.optimizationIdea} onChange={e => setForm({ ...form, optimizationIdea: e.target.value })} />
                </div>
              </div>

              <div className="form-group">
                <label className="form-label">Time Taken (minutes)</label>
                <input className="form-input" type="number" placeholder="30" value={form.timeTaken}
                  onChange={e => setForm({ ...form, timeTaken: e.target.value })} />
              </div>

              <div className="flex gap-2">
                <button type="submit" className="btn btn-primary" disabled={submitting}>
                  {submitting ? 'Saving...' : (editingId ? '💾 Update Problem' : '💾 Save Problem')}
                </button>
                <button
                  type="button"
                  className="btn btn-outline"
                  onClick={() => {
                    setShowModal(false);
                    setEditingId(null);
                    setForm(EMPTY_FORM);
                  }}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

function ProblemCard({ problem, onDelete, onEdit, staggerIndex }) {
  const [expanded, setExpanded] = useState(false);
  const difficultyClass = `diff-${(problem.difficulty || '').toLowerCase()}`;
  const statusClass = `status-${(problem.status || '').toLowerCase().replace(/\s+/g, '-')}`;
  const accent = getCardAccent(problem);
  return (
    <div
      className={`problem-card ${difficultyClass} ${statusClass}`}
      style={{
        '--problem-accent': accent.color,
        '--problem-accent-soft': accent.soft,
        '--stagger-index': staggerIndex,
      }}
    >
      <div className="problem-top">
        <span className={`tag ${DIFF_COLOR[problem.difficulty]}`}>{problem.difficulty}</span>
        <span className={`tag ${problem.status === 'Solved' ? 'tag-green' : problem.status === 'Attempted' ? 'tag-orange' : 'tag-red'}`}>{problem.status}</span>
        <span className="tag tag-orange">+{problem.xpEarned} XP</span>
      </div>

      <div className="problem-title-row">
        <div className="problem-title">{problem.title}</div>
        {problem.link && (
          <a href={problem.link} target="_blank" rel="noreferrer" className="problem-link" title="Open problem">
            <FiExternalLink />
          </a>
        )}
      </div>

      <div className="problem-meta">
        <span className="tag tag-purple">{problem.patternUsed}</span>
        <span className="tag tag-blue">{problem.topic}</span>
        {problem.timeTaken > 0 && <span className="tag"><FiClock className="inline-icon" /> {problem.timeTaken}m</span>}
      </div>

      <div className="problem-actions">
        <button className="btn btn-outline btn-sm" onClick={() => setExpanded(!expanded)}>
          {expanded ? 'Hide Notes' : 'View Notes'}
        </button>
        <button className="btn btn-outline btn-sm" onClick={() => onEdit(problem)}>
          <FiEdit3 /> Edit
        </button>
        <button className="btn btn-danger btn-sm" onClick={() => onDelete(problem._id)}>
          <FiTrash2 /> Delete
        </button>
      </div>

      {expanded && (
        <div className="problem-insights">
          {problem.learningInsight && <InsightBlock icon="💡" label="Learning" text={problem.learningInsight} />}
          {problem.mistakesMade && <InsightBlock icon="❌" label="Mistakes" text={problem.mistakesMade} />}
          {problem.optimizationIdea && <InsightBlock icon="⚡" label="Optimization" text={problem.optimizationIdea} />}
          {!problem.learningInsight && !problem.mistakesMade && !problem.optimizationIdea && (
            <div className="insight-block">
              <span className="insight-label">No Notes Yet</span>
              <p>Add learning notes while logging next problems to make revision easier.</p>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function InsightBlock({ icon, label, text }) {
  return (
    <div className="insight-block">
      <span className="insight-label">{icon} {label}</span>
      <p>{text}</p>
    </div>
  );
}

function StatMini({ label, value, icon }) {
  return (
    <div className="stat-card">
      <div className="stat-icon">{icon}</div>
      <div className="stat-value">{value}</div>
      <div className="stat-label">{label}</div>
    </div>
  );
}

function getCardAccent(problem) {
  const key = `${problem.title || ''}-${problem.patternUsed || ''}-${problem.topic || ''}`;
  let hash = 0;
  for (let i = 0; i < key.length; i += 1) {
    hash = (hash << 5) - hash + key.charCodeAt(i);
    hash |= 0;
  }
  return CARD_ACCENTS[Math.abs(hash) % CARD_ACCENTS.length];
}
